          "border-primary bg-primary text-primary-foreground",
        state === "active" &&
          "border-primary bg-background text-primary",
        state === "pending" &&
          "border-muted-foreground/30 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// ─── StepperTitle ──────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ──────────────────────────────────────────────────────
// Placed inside a StepperItem. Inherits state from StepperItemContext.
// "Completed" when the containing step is completed (i.e., next step is active).

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "flex-1 transition-colors",
        orientation === "horizontal"
          ? "h-px min-w-[2rem]"
          : "w-px min-h-[2rem] self-stretch",
        state === "completed" ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ────────────────────────────────────────────────────────

function StepperContent({
  step,
  className,
  ...props
