    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    />
  )
}

// ─── Exports ───────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
