```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { step: 1, title: "Account", description: "Create your account" },
  { step: 2, title: "Profile", description: "Set up your profile" },
  { step: 3, title: "Complete", description: "Review and finish" },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-lg flex-col gap-8">
      <Stepper activeStep={activeStep}>
        {/* Horizontal indicator row */}
        <div className="flex w-full items-center">
          {steps.map(({ step, title, description }, index) => (
            <React.Fragment key={step}>
              <StepperItem step={step} className="flex-col items-start gap-1">
                <div className="flex items-center gap-2">
                  <StepperTrigger onClick={() => setActiveStep(step)} />
                  <div className="flex flex-col gap-0.5">
                    <StepperTitle>{title}</StepperTitle>
                    <StepperDescription>{description}</StepperDescription>
                  </div>
                </div>
                {index < steps.length - 1 && (
                  <StepperSeparator className="ml-4 mt-1" />
                )}
              </StepperItem>
            </React.Fragment>
          ))}
        </div>

        {/* Step content panels */}
        <StepperContent step={1} className="rounded-lg border p-4">
          <p className="text-sm text-muted-foreground">
            Enter your email address and choose a password to create your
            account.
          </p>
        </StepperContent>
        <StepperContent step={2} className="rounded-lg border p-4">
          <p className="text-sm text-muted-foreground">
            Add your name, profile picture, and other details to personalize
            your experience.
          </p>
        </StepperContent>
        <StepperContent step={3} className="rounded-lg border p-4">
          <p className="text-sm text-muted-foreground">
            Review your information and click Finish to complete your setup.
          </p>
        </StepperContent>
      </Stepper>

      {/* Navigation buttons */}
      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

**Notes:**
- Uses `export default` (matches all existing example files — they use default export)
- Imports `Button` from `@/registry/new-york-v4/ui/button`
- `React.useState` for `activeStep` management
- `StepperSeparator` is placed inside `StepperItem` (not for the last step) so it reads `state` from context
- `StepperContent` panels are inside `<Stepper>` so they can access the `StepperContext`

