"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    content:
      "Set up your account credentials. Enter your email address and create a secure password to get started.",
  },
  {
    step: 2,
    title: "Profile",
    content:
      "Complete your profile details. Add your name, avatar, and any other information to personalise your experience.",
  },
  {
    step: 3,
    title: "Complete",
    content:
      "You're all set! Your account has been created successfully. Welcome aboard — enjoy the experience.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  function handleNext() {
    setActiveStep((prev) => Math.min(prev + 1, steps.length))
  }

  function handlePrevious() {
    setActiveStep((prev) => Math.max(prev - 1, 1))
  }

  return (
    <div className="w-full max-w-xl space-y-6 p-4">
      <Stepper activeStep={activeStep} orientation="horizontal">
        <div className="flex items-center">
          {steps.map(({ step, title }, index) => (
            <StepperItem
              key={step}
              step={step}
              className={
                index < steps.length - 1
                  ? "flex flex-1 items-center"
                  : "flex items-center"
              }
            >
              <div className="flex shrink-0 flex-col items-center gap-1.5">
                <StepperTrigger aria-label={`Go to step ${step}: ${title}`} />
                <StepperTitle>{title}</StepperTitle>
              </div>
              {index < steps.length - 1 && (
                <StepperSeparator className="mx-3" />
              )}
            </StepperItem>
          ))}
        </div>

        {steps.map(({ step, content }) => (
          <StepperContent key={step} step={step}>
            <p className="rounded-lg border bg-muted/40 p-4 text-sm text-muted-foreground">
              {content}
            </p>
          </StepperContent>
        ))}
      </Stepper>

      <div className="flex items-center gap-2">
        <Button
          variant="outline"
          onClick={handlePrevious}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button onClick={handleNext} disabled={activeStep === steps.length}>
          Next
        </Button>
      </div>
    </div>
  )
}

