"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("Stepper components must be used within a <Stepper />")
  }

  return context
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItemContext() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error(
      "StepperItem sub-components must be used within a <StepperItem />"
    )
  }

  return context
}

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepperContext()

  const state: "completed" | "active" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(className)}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItemContext()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "bg-primary text-primary-foreground hover:bg-primary/90",
        state === "active" &&
          "border-2 border-primary bg-background text-primary",
        state === "pending" &&
          "border-2 border-muted-foreground/30 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()
  const { state } = useStepperItemContext()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "flex-1 transition-colors",
        orientation === "horizontal" ? "h-px" : "w-px",
        state === "completed" ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepperContext()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
